const STORAGE_KEYS = {
  PROFILE: "artist_profile",
  PROFILE_IMAGE_VERSION: "artist_profile_image_version",
  PORTFOLIO: "artist_portfolio",
  PORTFOLIO_VERSION: "artist_portfolio_version",
  WEBTOON: "artist_webtoon",
  WEBTOON_SERIES: "artist_webtoon_series",
  WEBTOON_EPISODES: "artist_webtoon_episodes",
  ILLUSTRATION: "artist_illustration",
  ILLUSTRATION_VERSION: "artist_illustration_version",
}

const PERSISTED_STORAGE_KEYS = [
  STORAGE_KEYS.PROFILE,
  STORAGE_KEYS.PROFILE_IMAGE_VERSION,
  STORAGE_KEYS.PORTFOLIO,
  STORAGE_KEYS.PORTFOLIO_VERSION,
  STORAGE_KEYS.WEBTOON,
  STORAGE_KEYS.WEBTOON_SERIES,
  STORAGE_KEYS.WEBTOON_EPISODES,
  STORAGE_KEYS.ILLUSTRATION,
  STORAGE_KEYS.ILLUSTRATION_VERSION,
] as const

const STORE_API_BASE = (process.env.NEXT_PUBLIC_STORE_API_BASE_URL || "/api").replace(/\/$/, "")
const STORE_API_URL = `${STORE_API_BASE}/store`

let hydrationPromise: Promise<void> | null = null

function readStoredValue(value: string): unknown {
  try {
    return JSON.parse(value)
  } catch {
    return undefined
  }
}

function readLocalStoreSnapshot(): Record<string, unknown> {
  const snapshot: Record<string, unknown> = {}

  for (const key of PERSISTED_STORAGE_KEYS) {
    const stored = localStorage.getItem(key)
    if (stored !== null) {
      const parsed = readStoredValue(stored)
      if (parsed !== undefined) {
        snapshot[key] = parsed
      }
    }
  }

  return snapshot
}

function writeLocalStoreSnapshot(snapshot: Record<string, unknown>): void {
  for (const key of PERSISTED_STORAGE_KEYS) {
    if (Object.prototype.hasOwnProperty.call(snapshot, key)) {
      localStorage.setItem(key, JSON.stringify(snapshot[key]))
    }
  }
}

async function persistStore(): Promise<void> {
  if (typeof window === "undefined") return

  try {
    await fetch(STORE_API_URL, {
      method: "PUT",
      headers: {
        "Content-Type": "application/json",
      },
      body: JSON.stringify(readLocalStoreSnapshot()),
    })
  } catch (error) {
    console.warn("Failed to sync store to server:", error)
  }
}

function queueStoreSync(): void {
  if (typeof window === "undefined") return

  void (hydrationPromise ? hydrationPromise.then(() => persistStore()) : persistStore())
}

export async function hydrateStore(): Promise<void> {
  if (typeof window === "undefined") return

  if (!hydrationPromise) {
    hydrationPromise = (async () => {
      try {
        const response = await fetch(STORE_API_URL, {
          headers: {
            Accept: "application/json",
          },
        })

        if (response.ok) {
          const snapshot = (await response.json()) as Record<string, unknown>
          if (snapshot && typeof snapshot === "object" && !Array.isArray(snapshot)) {
            writeLocalStoreSnapshot(snapshot)
          }
        }
      } catch (error) {
        console.warn("Failed to hydrate store from server:", error)
      }

      // Seed defaults when the browser cache is empty, then mirror the result back to the server.
      getProfile()
      getPortfolioPosts()
      getIllustrationPosts()
      getWebtoonSeriesList()
      getAllWebtoonEpisodes()

      await persistStore()
    })()
  }

  await hydrationPromise
}

