// Profile functions
export function getProfile(): Profile {
  if (typeof window === "undefined") {
    return DEFAULT_PROFILE
  }

  const stored = localStorage.getItem(STORAGE_KEYS.PROFILE)
  const shouldApplyDefaultImage =
    localStorage.getItem(STORAGE_KEYS.PROFILE_IMAGE_VERSION) !== DEFAULT_PROFILE_IMAGE_VERSION

  if (!stored) {
    if (shouldApplyDefaultImage) {
      localStorage.setItem(STORAGE_KEYS.PROFILE_IMAGE_VERSION, DEFAULT_PROFILE_IMAGE_VERSION)
      localStorage.setItem(STORAGE_KEYS.PROFILE, JSON.stringify(DEFAULT_PROFILE))
    }
    return DEFAULT_PROFILE
  }

  try {
    const parsed = JSON.parse(stored) as Partial<Profile>

    const mergedProfile: Profile = {
      ...DEFAULT_PROFILE,
      ...parsed,
      imageUrl:
        typeof parsed.imageUrl === "string" && parsed.imageUrl.trim()
          ? parsed.imageUrl
          : DEFAULT_PROFILE.imageUrl,
      text: typeof parsed.text === "string" ? parsed.text : DEFAULT_PROFILE.text,
    }

    if (shouldApplyDefaultImage) {
      const migratedProfile: Profile = {
        ...mergedProfile,
        imageUrl: DEFAULT_PROFILE.imageUrl,
        name: mergedProfile.name || DEFAULT_PROFILE.name,
        shortIntro: mergedProfile.shortIntro || DEFAULT_PROFILE.shortIntro,
      }
      localStorage.setItem(STORAGE_KEYS.PROFILE_IMAGE_VERSION, DEFAULT_PROFILE_IMAGE_VERSION)
      localStorage.setItem(STORAGE_KEYS.PROFILE, JSON.stringify(migratedProfile))
      return migratedProfile
    }

    return mergedProfile
  } catch {
    return DEFAULT_PROFILE
  }
}

export function saveProfile(profile: Profile): void {
  if (typeof window === "undefined") return
  localStorage.setItem(STORAGE_KEYS.PROFILE, JSON.stringify(profile))
  queueStoreSync()
}

// Generic post functions
function getPosts(key: string): Post[] {
  if (typeof window === "undefined") return []
  const stored = localStorage.getItem(key)
  return stored ? JSON.parse(stored) : []
}

function savePosts(key: string, posts: Post[]): void {
  if (typeof window === "undefined") return
  try {
    localStorage.setItem(key, JSON.stringify(posts))
    queueStoreSync()
  } catch (error) {
    console.error("Storage quota exceeded:", error)
    alert("브라우저 저장 공간이 가득 찼습니다. 기존 게시글이나 이미지를 삭제한 후 다시 시도해주세요. (브라우저 로컬 데이터 정리 권장)")
    throw error // Re-throw to inform the caller
  }
}

// Portfolio
export function getPortfolioPosts(): Post[] {
  if (typeof window === "undefined") {
    return DEFAULT_PORTFOLIO_POSTS
  }

  const stored = localStorage.getItem(STORAGE_KEYS.PORTFOLIO)
  const shouldApplyDefaultPortfolio =
    localStorage.getItem(STORAGE_KEYS.PORTFOLIO_VERSION) !== DEFAULT_PORTFOLIO_VERSION

  if (!stored) {
    if (shouldApplyDefaultPortfolio) {
      localStorage.setItem(STORAGE_KEYS.PORTFOLIO, JSON.stringify(DEFAULT_PORTFOLIO_POSTS))
      localStorage.setItem(STORAGE_KEYS.PORTFOLIO_VERSION, DEFAULT_PORTFOLIO_VERSION)
    }
    return DEFAULT_PORTFOLIO_POSTS
  }

  try {
    const parsed = JSON.parse(stored) as Post[]
    const posts = Array.isArray(parsed) ? parsed : []

    if (shouldApplyDefaultPortfolio) {
      const missingDefaults = DEFAULT_PORTFOLIO_POSTS.filter(
        (defaultPost) => !posts.some((post) => post.id === defaultPost.id),
      )
      const mergedPosts = [...missingDefaults, ...posts]

      localStorage.setItem(STORAGE_KEYS.PORTFOLIO, JSON.stringify(mergedPosts))
      localStorage.setItem(STORAGE_KEYS.PORTFOLIO_VERSION, DEFAULT_PORTFOLIO_VERSION)
      return mergedPosts
    }

    return posts
  } catch {
    return DEFAULT_PORTFOLIO_POSTS
  }
}

export function savePortfolioPost(post: Post): void {
  const posts = getPortfolioPosts()
  posts.unshift(post)
  savePosts(STORAGE_KEYS.PORTFOLIO, posts)
}

export function deletePortfolioPost(id: string): void {
  const posts = getPortfolioPosts().filter(p => p.id !== id)
  savePosts(STORAGE_KEYS.PORTFOLIO, posts)
}

