// Illustration
export function getIllustrationPosts(): Post[] {
  if (typeof window === "undefined") {
    return DEFAULT_ILLUSTRATION_POSTS
  }

  const stored = localStorage.getItem(STORAGE_KEYS.ILLUSTRATION)
  const shouldApplyDefaultIllustration =
    localStorage.getItem(STORAGE_KEYS.ILLUSTRATION_VERSION) !== DEFAULT_ILLUSTRATION_VERSION

  if (!stored || shouldApplyDefaultIllustration) {
    localStorage.setItem(STORAGE_KEYS.ILLUSTRATION, JSON.stringify(DEFAULT_ILLUSTRATION_POSTS))
    localStorage.setItem(STORAGE_KEYS.ILLUSTRATION_VERSION, DEFAULT_ILLUSTRATION_VERSION)
    return DEFAULT_ILLUSTRATION_POSTS
  }

  try {
    const parsed = JSON.parse(stored) as Post[]
    return Array.isArray(parsed) ? parsed : DEFAULT_ILLUSTRATION_POSTS
  } catch {
    localStorage.setItem(STORAGE_KEYS.ILLUSTRATION, JSON.stringify(DEFAULT_ILLUSTRATION_POSTS))
    return DEFAULT_ILLUSTRATION_POSTS
  }
}

export function saveIllustrationPost(post: Post): void {
  const posts = getIllustrationPosts()
  posts.unshift(post)
  savePosts(STORAGE_KEYS.ILLUSTRATION, posts)
}

export function deleteIllustrationPost(id: string): void {
  const posts = getIllustrationPosts().filter(p => p.id !== id)
  savePosts(STORAGE_KEYS.ILLUSTRATION, posts)
}

export function addCommentToIllustration(postId: string, comment: Comment): void {
  const posts = getIllustrationPosts()
  const postIndex = posts.findIndex(p => p.id === postId)
  if (postIndex !== -1) {
    if (!posts[postIndex].comments) {
      posts[postIndex].comments = []
    }
    posts[postIndex].comments!.push(comment)
    savePosts(STORAGE_KEYS.ILLUSTRATION, posts)
  }
}

// Webtoon Series
export function getWebtoonSeriesList(): WebtoonSeries[] {
  if (typeof window === "undefined") return []
  const stored = localStorage.getItem(STORAGE_KEYS.WEBTOON_SERIES)
  return stored ? JSON.parse(stored) : []
}

export function saveWebtoonSeries(series: WebtoonSeries): void {
  const list = getWebtoonSeriesList()
  list.unshift(series)
  if (typeof window !== "undefined") {
    localStorage.setItem(STORAGE_KEYS.WEBTOON_SERIES, JSON.stringify(list))
    queueStoreSync()
  }
}

export function deleteWebtoonSeries(id: string): void {
  const list = getWebtoonSeriesList().filter(s => s.id !== id)
  if (typeof window !== "undefined") {
    localStorage.setItem(STORAGE_KEYS.WEBTOON_SERIES, JSON.stringify(list))
    const remainingEpisodes = getAllWebtoonEpisodes().filter(ep => ep.seriesId !== id)
    localStorage.setItem(STORAGE_KEYS.WEBTOON_EPISODES, JSON.stringify(remainingEpisodes))
    queueStoreSync()
  }
}

// Webtoon Episodes
export function getWebtoonEpisodes(seriesId: string): WebtoonEpisode[] {
  if (typeof window === "undefined") return []
  const stored = localStorage.getItem(STORAGE_KEYS.WEBTOON_EPISODES)
  const allEpisodes: WebtoonEpisode[] = stored ? JSON.parse(stored) : []
  return allEpisodes.filter(ep => ep.seriesId === seriesId)
}

export function getAllWebtoonEpisodes(): WebtoonEpisode[] {
  if (typeof window === "undefined") return []
  const stored = localStorage.getItem(STORAGE_KEYS.WEBTOON_EPISODES)
  return stored ? JSON.parse(stored) : []
}

export function saveWebtoonEpisode(episode: WebtoonEpisode): void {
  const allEpisodes = getAllWebtoonEpisodes()
  allEpisodes.unshift(episode)
  if (typeof window !== "undefined") {
    localStorage.setItem(STORAGE_KEYS.WEBTOON_EPISODES, JSON.stringify(allEpisodes))
    queueStoreSync()
  }
}

export function deleteWebtoonEpisode(id: string): void {
  const allEpisodes = getAllWebtoonEpisodes().filter(ep => ep.id !== id)
  if (typeof window !== "undefined") {
    localStorage.setItem(STORAGE_KEYS.WEBTOON_EPISODES, JSON.stringify(allEpisodes))
    queueStoreSync()
  }
}

// Generate unique ID
export function generateId(): string {
  return Date.now().toString(36) + Math.random().toString(36).substring(2)
}
